SELECT p.*, cat.category_nm AS cate_nm, b.brand_nm, v.vendor_nm, u.user_nm AS md_user_nm, cd_ps.code_label AS prod_status_cd_nm, cd_pt.code_label AS prod_type_cd_nm FROM pd_prod p LEFT JOIN pd_category cat ON cat.category_id = p.category_id LEFT JOIN sy_brand b ON b.brand_id = p.brand_id LEFT JOIN sy_vendor v ON v.vendor_id = p.vendor_id LEFT JOIN sy_user u ON u.user_id = p.md_user_id LEFT JOIN sy_code cd_ps ON cd_ps.code_grp = 'PRODUCT_STATUS' AND cd_ps.code_value = p.prod_status_cd LEFT JOIN sy_code cd_pt ON cd_pt.code_grp = 'PRODUCT_TYPE' AND cd_pt.code_value = p.prod_type_cd
ORDER BY p.prod_id ASC ORDER BY p.prod_id DESC ORDER BY p.prod_nm ASC ORDER BY p.prod_nm DESC ORDER BY p.reg_date ASC ORDER BY p.reg_date DESC ORDER BY p.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT p.*, cat.category_nm AS cate_nm, b.brand_nm, v.vendor_nm, u.user_nm AS md_user_nm, cd_ps.code_label AS prod_status_cd_nm, cd_pt.code_label AS prod_type_cd_nm FROM pd_prod p LEFT JOIN pd_category cat ON cat.category_id = p.category_id LEFT JOIN sy_brand b ON b.brand_id = p.brand_id LEFT JOIN sy_vendor v ON v.vendor_id = p.vendor_id LEFT JOIN sy_user u ON u.user_id = p.md_user_id LEFT JOIN sy_code cd_ps ON cd_ps.code_grp = 'PRODUCT_STATUS' AND cd_ps.code_value = p.prod_status_cd LEFT JOIN sy_code cd_pt ON cd_pt.code_grp = 'PRODUCT_TYPE' AND cd_pt.code_value = p.prod_type_cd
ORDER BY p.prod_id ASC ORDER BY p.prod_id DESC ORDER BY p.prod_nm ASC ORDER BY p.prod_nm DESC ORDER BY p.reg_date ASC ORDER BY p.reg_date DESC ORDER BY p.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

