UPDATE pd_prod
prod_status_cd = #{prodStatusCd}, prod_status_cd_before = #{prodStatusCdBefore}, prod_nm = #{prodNm}, sale_price = #{salePrice}, prod_stock = #{prodStock}, thumbnail_url = #{thumbnailUrl}, is_best = #{isBest}, is_new = #{isNew}, sold_out_yn = #{soldOutYn}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE prod_id = #{prodId}
